  @doc false
  def provenance, do: %{go: @go_version, unicode: @unicode_version}

  @doc false
  def class_names, do: @class_names

  @doc false
  def lookup(name) when is_binary(name) do
    case canonical_name(name) do
      "Any" -> {:ok, @any, false}
      "Assigned" -> {:ok, @cn, true}
      "Ascii" -> {:ok, @ascii, false}
      canonical ->
        canonical = Map.get(@aliases, canonical, canonical)
        case Map.fetch(@tables, canonical) do
          {:ok, ranges} -> {:ok, ranges, false}
          :error -> :error
        end
    end
  end

  @doc false
  def space?(codepoint) when is_integer(codepoint), do: member?(@white_space, codepoint)

  @doc false
  def member?(ranges, codepoint) when is_tuple(ranges) and is_integer(codepoint) do
    if codepoint in 0..0x10FFFF, do: member?(ranges, codepoint, 0, tuple_size(ranges) - 1), else: false
  end

  defp member?(_ranges, _codepoint, low, high) when low > high, do: false

  defp member?(ranges, codepoint, low, high) do
    middle = div(low + high, 2)
    {first, last, stride} = elem(ranges, middle)

    cond do
      codepoint < first -> member?(ranges, codepoint, low, middle - 1)
      codepoint > last -> member?(ranges, codepoint, middle + 1, high)
      true -> rem(codepoint - first, stride) == 0
    end
  end

  defp canonical_name(name) do
    {bytes, _first?} =
      for <<byte <- name>>, reduce: {[], true} do
        {bytes, first?} when byte in [95, 45, 32] -> {bytes, first?}
        {bytes, true} -> {[uppercase(byte) | bytes], false}
        {bytes, false} -> {[lowercase(byte) | bytes], false}
      end

    bytes |> Enum.reverse() |> :erlang.list_to_binary()
  end

  defp uppercase(byte) when byte in ?a..?z, do: byte - (?a - ?A)
  defp uppercase(byte), do: byte
  defp lowercase(byte) when byte in ?A..?Z, do: byte + (?a - ?A)
  defp lowercase(byte), do: byte
end
